package modlog

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/modlog"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type ModlogProxy struct {
	modlog.UnimplementedModlogServer
	client modlog.ModlogClient
}

func init() {
	proxyutil.Register(&modlog.Modlog_ServiceDesc, NewModlogProxy)
}
func NewModlogProxy(cc grpc.ClientConnInterface) modlog.ModlogServer {
	return &ModlogProxy{client: modlog.NewModlogClient(cc)}
}
func (p *ModlogProxy) Add(ctx context.Context, in *modlog.ModlogRequest) (*modlog.ModlogResponse, error) {
	return proxyutil.ProxyMethod[modlog.ModlogRequest, modlog.ModlogResponse](p.client.Add)(ctx, in)
}
